COPY supabase_migrations.schema_migrations (version, statements, name) FROM stdin;
0001	{"create extension if not exists pgcrypto","create type source_type as enum ('pdf', 'webpage', 'manual')","create type parse_status as enum ('pending', 'parsed', 'failed')","create type run_trigger_type as enum ('manual', 'batch', 'scheduled')","create type run_scope_type as enum ('vendor', 'county', 'all')","create type run_status as enum ('queued', 'running', 'completed', 'failed')","create type enrichment_stage as enum ('website', 'crawl', 'pricing', 'booking', 'finalize')","create type stage_status as enum ('queued', 'running', 'completed', 'failed', 'skipped')","create type retrieval_method as enum ('http', 'playwright')","create type extractor_type as enum ('deterministic', 'ai')","create type booking_capability as enum ('direct_booking', 'inquiry_only', 'none', 'unclear')","create type review_status as enum ('open', 'in_review', 'resolved', 'dismissed')","create type review_severity as enum ('low', 'medium', 'high', 'critical')","create type export_target_type as enum ('csv', 'google_sheets')","create type export_status as enum ('queued', 'running', 'completed', 'failed')","create type county_listing_status as enum ('active', 'inactive', 'unknown')","create type vendor_status as enum ('new', 'ready_for_enrichment', 'enriched', 'needs_review')","create table counties (\n  id uuid primary key default gen_random_uuid(),\n  name text not null,\n  state text not null default 'CA',\n  slug text not null unique,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","create table county_sources (\n  id uuid primary key default gen_random_uuid(),\n  county_id uuid not null references counties(id) on delete cascade,\n  source_type source_type not null,\n  source_url text,\n  storage_path text,\n  published_at timestamptz,\n  fetched_at timestamptz not null default now(),\n  checksum text,\n  parse_status parse_status not null default 'pending',\n  notes text,\n  created_at timestamptz not null default now()\n)","create table county_source_records (\n  id uuid primary key default gen_random_uuid(),\n  county_source_id uuid not null references county_sources(id) on delete cascade,\n  row_index integer not null,\n  raw_text text not null,\n  raw_json jsonb not null default '{}'::jsonb,\n  parse_confidence numeric(4,3),\n  parse_warnings text[],\n  created_at timestamptz not null default now()\n)","create unique index county_source_records_unique_row on county_source_records(county_source_id, row_index)","create table vendors (\n  id uuid primary key default gen_random_uuid(),\n  canonical_name text not null,\n  normalized_name text not null,\n  website_url text,\n  website_confidence numeric(4,3),\n  hq_city text,\n  status vendor_status not null default 'new',\n  last_enriched_at timestamptz,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n)","create unique index vendors_normalized_name_idx on vendors(normalized_name)","create table vendor_county_listings (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  county_id uuid not null references counties(id) on delete cascade,\n  county_source_id uuid not null references county_sources(id) on delete cascade,\n  source_record_id uuid references county_source_records(id) on delete set null,\n  listing_status county_listing_status not null default 'active',\n  first_seen_at timestamptz not null default now(),\n  last_seen_at timestamptz not null default now(),\n  created_at timestamptz not null default now()\n)","create unique index vendor_county_listing_unique on vendor_county_listings(vendor_id, county_id, county_source_id)","create table vendor_contacts (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  name text,\n  role text,\n  email text,\n  phone text,\n  is_primary boolean not null default false,\n  source_record_id uuid references county_source_records(id) on delete set null,\n  verified_at timestamptz,\n  created_at timestamptz not null default now()\n)","create table enrichment_runs (\n  id uuid primary key default gen_random_uuid(),\n  trigger_type run_trigger_type not null,\n  scope_type run_scope_type not null,\n  scope_ref text,\n  status run_status not null default 'queued',\n  started_at timestamptz,\n  completed_at timestamptz,\n  error_summary text,\n  created_at timestamptz not null default now()\n)","create table vendor_enrichments (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  run_id uuid not null references enrichment_runs(id) on delete cascade,\n  stage enrichment_stage not null,\n  status stage_status not null default 'queued',\n  attempt integer not null default 1,\n  started_at timestamptz,\n  completed_at timestamptz,\n  diagnostics_json jsonb not null default '{}'::jsonb,\n  created_at timestamptz not null default now()\n)","create unique index vendor_enrichments_unique_attempt on vendor_enrichments(vendor_id, run_id, stage, attempt)","create table crawl_pages (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  run_id uuid not null references enrichment_runs(id) on delete cascade,\n  url text not null,\n  final_url text,\n  http_status integer,\n  content_type text,\n  retrieval_method retrieval_method not null,\n  page_title text,\n  content_hash text,\n  raw_text text,\n  fetched_at timestamptz not null default now()\n)","create table vendor_field_evidence (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  run_id uuid not null references enrichment_runs(id) on delete cascade,\n  field_key text not null,\n  value_text text,\n  value_json jsonb,\n  source_url text not null,\n  source_type source_type not null default 'webpage',\n  evidence_snippet text,\n  confidence numeric(4,3) not null,\n  extractor_type extractor_type not null,\n  extracted_at timestamptz not null default now(),\n  is_current boolean not null default true\n)","create index vendor_field_evidence_vendor_field_idx on vendor_field_evidence(vendor_id, field_key, is_current)","create table vendor_price_records (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  run_id uuid not null references enrichment_runs(id) on delete cascade,\n  course_type text not null,\n  price_cents integer,\n  currency text not null default 'USD',\n  price_text text,\n  source_url text not null,\n  confidence numeric(4,3) not null,\n  evidence_id uuid references vendor_field_evidence(id) on delete set null,\n  checked_at timestamptz not null default now()\n)","create table vendor_booking_records (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  run_id uuid not null references enrichment_runs(id) on delete cascade,\n  booking_capability booking_capability not null,\n  booking_url text,\n  provider_hint text,\n  confidence numeric(4,3) not null,\n  evidence_id uuid references vendor_field_evidence(id) on delete set null,\n  checked_at timestamptz not null default now()\n)","create table review_queue (\n  id uuid primary key default gen_random_uuid(),\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  run_id uuid references enrichment_runs(id) on delete set null,\n  reason_code text not null,\n  severity review_severity not null default 'medium',\n  status review_status not null default 'open',\n  payload_json jsonb not null default '{}'::jsonb,\n  assigned_to text,\n  created_at timestamptz not null default now(),\n  resolved_at timestamptz\n)","create unique index review_queue_open_dedupe_idx on review_queue(vendor_id, reason_code) where status in ('open', 'in_review')","create table review_actions (\n  id uuid primary key default gen_random_uuid(),\n  review_item_id uuid not null references review_queue(id) on delete cascade,\n  action_type text not null,\n  before_json jsonb,\n  after_json jsonb,\n  actor text not null default 'system',\n  created_at timestamptz not null default now()\n)","create table export_jobs (\n  id uuid primary key default gen_random_uuid(),\n  target_type export_target_type not null,\n  status export_status not null default 'queued',\n  started_at timestamptz,\n  completed_at timestamptz,\n  row_count integer,\n  error_summary text,\n  created_at timestamptz not null default now()\n)"}	init
0002	{"-- Lightweight job table that the worker polls.\n-- Each row = one vendor enrichment to perform within a run.\ncreate table if not exists enrichment_jobs (\n  id uuid primary key default gen_random_uuid(),\n  run_id uuid not null references enrichment_runs(id) on delete cascade,\n  vendor_id uuid not null references vendors(id) on delete cascade,\n  status run_status not null default 'queued',\n  claimed_at timestamptz,\n  started_at timestamptz,\n  completed_at timestamptz,\n  attempts integer not null default 0,\n  max_attempts integer not null default 3,\n  error_summary text,\n  created_at timestamptz not null default now()\n)","create index enrichment_jobs_poll_idx\n  on enrichment_jobs(status, created_at)\n  where status = 'queued'","create unique index enrichment_jobs_run_vendor_idx\n  on enrichment_jobs(run_id, vendor_id)","-- RPC: atomically claim the next N queued jobs (skip locked).\ncreate or replace function claim_enrichment_jobs(batch_size int default 1)\nreturns setof enrichment_jobs\nlanguage sql volatile\nas $$\n  update enrichment_jobs\n  set status = 'running',\n      claimed_at = now(),\n      attempts = attempts + 1\n  where id in (\n    select id from enrichment_jobs\n    where status = 'queued'\n    order by created_at\n    for update skip locked\n    limit batch_size\n  )\n  returning *;\n$$","-- RPC: enqueue all vendors for a county that have not already been\n-- queued/completed in the given run.\ncreate or replace function enqueue_county_vendors(\n  p_run_id uuid,\n  p_county_id uuid,\n  p_max_attempts int default 3\n)\nreturns int\nlanguage plpgsql volatile\nas $$\ndeclare\n  inserted int;\nbegin\n  insert into enrichment_jobs (run_id, vendor_id, max_attempts)\n  select p_run_id, v.id, p_max_attempts\n  from vendors v\n  join vendor_county_listings vcl on vcl.vendor_id = v.id\n  where vcl.county_id = p_county_id\n    and v.status in ('new', 'ready_for_enrichment', 'needs_review')\n    and not exists (\n      select 1 from enrichment_jobs ej\n      where ej.run_id = p_run_id and ej.vendor_id = v.id\n    )\n  on conflict (run_id, vendor_id) do nothing;\n\n  get diagnostics inserted = row_count;\n  return inserted;\nend;\n$$"}	enrichment_jobs
0003	{"-- All 58 California counties. Safe to re-run: skips rows that already match slug.\ninsert into counties (name, state, slug) values\n  ('Alameda', 'CA', 'alameda'),\n  ('Alpine', 'CA', 'alpine'),\n  ('Amador', 'CA', 'amador'),\n  ('Butte', 'CA', 'butte'),\n  ('Calaveras', 'CA', 'calaveras'),\n  ('Colusa', 'CA', 'colusa'),\n  ('Contra Costa', 'CA', 'contra-costa'),\n  ('Del Norte', 'CA', 'del-norte'),\n  ('El Dorado', 'CA', 'el-dorado'),\n  ('Fresno', 'CA', 'fresno'),\n  ('Glenn', 'CA', 'glenn'),\n  ('Humboldt', 'CA', 'humboldt'),\n  ('Imperial', 'CA', 'imperial'),\n  ('Inyo', 'CA', 'inyo'),\n  ('Kern', 'CA', 'kern'),\n  ('Kings', 'CA', 'kings'),\n  ('Lake', 'CA', 'lake'),\n  ('Lassen', 'CA', 'lassen'),\n  ('Los Angeles', 'CA', 'los-angeles'),\n  ('Madera', 'CA', 'madera'),\n  ('Marin', 'CA', 'marin'),\n  ('Mariposa', 'CA', 'mariposa'),\n  ('Mendocino', 'CA', 'mendocino'),\n  ('Merced', 'CA', 'merced'),\n  ('Modoc', 'CA', 'modoc'),\n  ('Mono', 'CA', 'mono'),\n  ('Monterey', 'CA', 'monterey'),\n  ('Napa', 'CA', 'napa'),\n  ('Nevada', 'CA', 'nevada'),\n  ('Orange', 'CA', 'orange'),\n  ('Placer', 'CA', 'placer'),\n  ('Plumas', 'CA', 'plumas'),\n  ('Riverside', 'CA', 'riverside'),\n  ('Sacramento', 'CA', 'sacramento'),\n  ('San Benito', 'CA', 'san-benito'),\n  ('San Bernardino', 'CA', 'san-bernardino'),\n  ('San Diego', 'CA', 'san-diego'),\n  ('San Francisco', 'CA', 'san-francisco'),\n  ('San Joaquin', 'CA', 'san-joaquin'),\n  ('San Luis Obispo', 'CA', 'san-luis-obispo'),\n  ('San Mateo', 'CA', 'san-mateo'),\n  ('Santa Barbara', 'CA', 'santa-barbara'),\n  ('Santa Clara', 'CA', 'santa-clara'),\n  ('Santa Cruz', 'CA', 'santa-cruz'),\n  ('Shasta', 'CA', 'shasta'),\n  ('Sierra', 'CA', 'sierra'),\n  ('Siskiyou', 'CA', 'siskiyou'),\n  ('Solano', 'CA', 'solano'),\n  ('Sonoma', 'CA', 'sonoma'),\n  ('Stanislaus', 'CA', 'stanislaus'),\n  ('Sutter', 'CA', 'sutter'),\n  ('Tehama', 'CA', 'tehama'),\n  ('Trinity', 'CA', 'trinity'),\n  ('Tulare', 'CA', 'tulare'),\n  ('Tuolumne', 'CA', 'tuolumne'),\n  ('Ventura', 'CA', 'ventura'),\n  ('Yolo', 'CA', 'yolo'),\n  ('Yuba', 'CA', 'yuba')\non conflict (slug) do nothing"}	seed_california_counties
0004	{"-- Flat enriched listings from ccw-scraper/data/enriched/all-vendors.csv (one row per vendor+county).\r\n-- Loaded via: npm run db:load-enriched\r\n\r\ncreate table enriched_vendor_county_listings (\r\n  id uuid primary key default gen_random_uuid(),\r\n  county text not null,\r\n  needs_review text,\r\n  vendor_name text not null,\r\n  instructor_names text,\r\n  email text,\r\n  phone text,\r\n  website_url text,\r\n  booking_capability text,\r\n  city text,\r\n  state text,\r\n  address text,\r\n  price_16hr_full text,\r\n  price_8hr_renewal text,\r\n  price_add_a_gun text,\r\n  vendor_description text,\r\n  crawl_status text,\r\n  enrichment_confidence text,\r\n  confidence_notes text,\r\n  logo_path text,\r\n  instructor_image_paths text,\r\n  training_image_paths text,\r\n  enriched_at timestamptz,\r\n  normalized_vendor_name text generated always as (lower(trim(vendor_name))) stored,\r\n  created_at timestamptz not null default now(),\r\n  updated_at timestamptz not null default now(),\r\n  constraint enriched_vendor_county_listings_uniq unique (county, normalized_vendor_name)\r\n)","create index enriched_vendor_county_listings_vendor_idx\r\n  on enriched_vendor_county_listings (normalized_vendor_name)","create or replace function enriched_vendor_county_listings_set_updated_at()\r\nreturns trigger\r\nlanguage plpgsql\r\nas $$\r\nbegin\r\n  new.updated_at = now();\r\n  return new;\r\nend;\r\n$$","create trigger enriched_vendor_county_listings_updated_at\r\n  before update on enriched_vendor_county_listings\r\n  for each row\r\n  execute procedure enriched_vendor_county_listings_set_updated_at()","alter table enriched_vendor_county_listings enable row level security","create policy enriched_vendor_county_listings_select_public\r\n  on enriched_vendor_county_listings\r\n  for select\r\n  to anon, authenticated\r\n  using (true)","comment on table enriched_vendor_county_listings is 'Public directory data synced from ccw-scraper enriched CSV; RLS allows read-only public select.'"}	enriched_vendor_county_listings
0005	{"alter table enriched_vendor_county_listings\r\n  add column if not exists google_place_id text,\r\n  add column if not exists google_reviews_url text","create index if not exists enriched_vendor_county_listings_google_place_id_idx\r\n  on enriched_vendor_county_listings (google_place_id)"}	add_google_place_columns
